const TECH_KEYWORDS = [
  'kubernetes', 'k8s', 'terraform', 'aws', 'azure', 'gcp',
  'docker', 'ansible', 'puppet', 'chef', 'linux', 'python',
  'golang', 'java', 'jenkins', 'github', 'gitlab',
  'ci/cd', 'cicd', 'cloudformation', 'helm', 'prometheus',
  'grafana', 'splunk', 'datadog', 'powershell', 'bash',
  'red hat', 'rhel', 'windows server', 'vmware', 'openshift',
  'iam', 'devsecops', 'jira', 'servicenow'
];
const DMV_KEYWORDS = [
  'washington', 'dc', 'd.c.', 'district of columbia',
  'maryland', 'virginia', 'arlington', 'alexandria',
  'fairfax', 'reston', 'tysons', 'mclean', 'herndon',
  'sterling', 'ashburn', 'leesburg', 'bethesda', 'rockville',
  'silver spring', 'college park', 'columbia', 'baltimore',
  'annapolis', 'fort meade', 'fort belvoir', 'pentagon',
  'springfield', 'chantilly', 'quantico'
];
const REMOTE_KEYWORDS = [
  'remote', 'telework', 'anywhere', 'negotiable',
  'multiple locations', 'virtual', 'work from home'
];
function extractTechnologies(text) {
  if (!text) return '';
  const lower = text.toLowerCase();
  const found = TECH_KEYWORDS.filter(kw => lower.includes(kw));
  return [...new Set(found)].join(', ');
}
function classifyLocation(locationDisplay) {
  const loc = (locationDisplay || '').toLowerCase();
  for (const kw of REMOTE_KEYWORDS) { if (loc.includes(kw)) return 'relevant'; }
  for (const kw of DMV_KEYWORDS) { if (loc.includes(kw)) return 'relevant'; }
  return 'skip';
}
function detectRemote(locationDisplay) {
  const loc = (locationDisplay || '').toLowerCase();
  for (const kw of REMOTE_KEYWORDS) { if (loc.includes(kw)) return 'Yes'; }
  return 'No';
}
function formatSalary(remuneration) {
  if (!remuneration || !remuneration.length) return '';
  const r = remuneration[0];
  const min = parseInt(r.MinimumRange);
  const max = parseInt(r.MaximumRange);
  const fmt = (n) => '$' + n.toLocaleString('en-US');
  if (min && max) return `${fmt(min)}\u2013${fmt(max)}`;
  if (min) return `${fmt(min)}+`;
  if (max) return `Up to ${fmt(max)}`;
  return '';
}
const allInputs = $input.all();
const allResults = [];
const dateReceived = new Date().toISOString().split('T')[0];
for (const input of allInputs) {
  let json = input.json;
  if (!json.SearchResult && typeof json.data === 'string') {
    try { json = JSON.parse(json.data); } catch (e) { /* keep original */ }
  }
  if (!json.SearchResult && json.data && typeof json.data === 'object' && json.data.SearchResult) {
    json = json.data;
  }
  if (!json.SearchResult) {
    allResults.push({ json: {
      _isNew: true,
      'Date Received': dateReceived, 'Company': '\u26a0 USAJOBS API ERROR',
      'Job Title': JSON.stringify(json).substring(0, 200),
      'URL': '', 'Location': '', 'Remote': '', 'Salary': '',
      'Experience': '', 'Technologies': '', 'Function': '',
      'Company Size': '', 'Funding': '', 'Progress': 'error',
      'Source': 'usajobs', 'Job ID': '', 'Apply URL': '', 'Applied': '', 'Security Clearance': ''
    }});
    continue;
  }
  const items = json.SearchResult.SearchResultItems || [];
  for (const item of items) { allResults.push(item); }
}
const seen = new Set();
const uniqueResults = [];
for (const item of allResults) {
  if (item.json && item.json._isNew) { uniqueResults.push(item); continue; }
  const id = item.MatchedObjectId;
  if (!id || seen.has(id)) continue;
  seen.add(id);
  uniqueResults.push(item);
}
const output = [];
for (const item of uniqueResults) {
  if (item.json && item.json._isNew) { output.push(item); continue; }
  const desc = item.MatchedObjectDescriptor || {};
  const details = desc.UserArea?.Details || {};
  const qualifications = desc.QualificationSummary || '';
  const locationDisplay = desc.PositionLocationDisplay || '';
  const orgName = desc.OrganizationName || '';
  const deptName = desc.DepartmentName || '';
  const company = deptName && deptName !== orgName ? `${orgName} (${deptName})` : orgName;
  const seriesCode = (desc.JobCategory || [])[0]?.Code || '';
  if (seriesCode !== '2210') continue;
  const lowGrade = details.LowGrade || '';
  const highGrade = details.HighGrade || '';
  if (lowGrade === '00' || highGrade === '00') continue;
  const maxGrade = parseInt(highGrade) || parseInt(lowGrade) || 0;
  if (maxGrade > 0 && maxGrade < 12) continue;
  const experience = lowGrade && highGrade && lowGrade !== highGrade
    ? `GS-${lowGrade} to GS-${highGrade}` : lowGrade ? `GS-${lowGrade}` : '';
  const jobCategory = (desc.JobCategory || [])[0];
  const functionName = jobCategory ? jobCategory.Name : '';
  const applyUri = (desc.ApplyURI || [])[0] || '';
  output.push({ json: {
    _isNew: true,
    'Date Received': dateReceived,
    'Company': company,
    'Job Title': desc.PositionTitle || '',
    'URL': desc.PositionURI || '',
    'Location': locationDisplay,
    'Salary': formatSalary(desc.PositionRemuneration),
    'Progress': classifyLocation(locationDisplay),
    'Remote': detectRemote(locationDisplay),
    'Experience': experience,
    'Technologies': extractTechnologies(qualifications),
    'Function': functionName,
    'Company Size': '',
    'Funding': '',
    'Source': 'usajobs',
    'Job ID': item.MatchedObjectId || '',
    'Apply URL': applyUri,
    'Applied': '',
    'Security Clearance': details.SecurityClearance || ''
  }});
}
if (output.length === 0) return [];
return output;

const allItems = $input.all();
const newItems = [];
const existingKeys = new Set();
const existingUrls = new Set();
for (const item of allItems) {
  if (item.json._isNew) { newItems.push(item); }
  else {
    const source = String(item.json['Source'] ?? '').trim();
    const jobId = String(item.json['Job ID'] ?? '').trim();
    const url = String(item.json['URL'] ?? '').trim();
    const key = source && jobId ? `${source}:${jobId}` : '';
    if (key) existingKeys.add(key);
    if (url) existingUrls.add(url);
  }
}
console.log(`Dedup: ${newItems.length} new items, ${existingKeys.size} existing keys, ${existingUrls.size} existing URLs`);
const output = [];
let skippedCount = 0;
for (const item of newItems) {
  const progress = item.json['Progress'] || '';
  if (progress === 'error') { const { _isNew, ...rest } = item.json; output.push({ json: rest }); continue; }
  const source = String(item.json['Source'] ?? '').trim();
  const jobId = String(item.json['Job ID'] ?? '').trim();
  const url = String(item.json['URL'] ?? '').trim();
  const key = source && jobId ? `${source}:${jobId}` : '';
  if (key && existingKeys.has(key)) { skippedCount++; continue; }
  if (!key && url && existingUrls.has(url)) { skippedCount++; continue; }
  const { _isNew, ...rest } = item.json;
  output.push({ json: rest });
}
console.log(`Dedup: skipped ${skippedCount} duplicate(s), passing ${output.length} new item(s)`);

if (output.length > 0) return output;

// No new jobs — emit at most one heartbeat row per calendar day
const today = new Date().toISOString().split('T')[0];
const alreadyHasHeartbeat = allItems.some(item =>
  !item.json._isNew &&
  String(item.json['Progress'] ?? '') === 'skip' &&
  String(item.json['Company'] ?? '') === '\u2713 No new jobs \u2014 USAJobs' &&
  String(item.json['Date Received'] ?? '').startsWith(today)
);

if (alreadyHasHeartbeat) return [];

return [{
  json: {
    'Date Received': today,
    'Company': '\u2713 No new jobs \u2014 USAJobs',
    'Job Title': 'Workflow ran \u2014 all recommendations already tracked',
    'URL': '', 'Location': '', 'Remote': '', 'Salary': '',
    'Experience': '', 'Technologies': '', 'Function': '',
    'Company Size': '', 'Funding': '',
    'Progress': 'skip', 'Source': 'usajobs',
    'Job ID': '', 'Apply URL': '', 'Applied': '', 'Security Clearance': ''
  }
}];
